+    #[tokio::test]
+    async fn sleep_completes() {
+        let start = std::time::Instant::now();
+        sleep(Duration::from_millis(10)).await;
+        let elapsed = start.elapsed();
+        assert!(elapsed >= Duration::from_millis(5));
+    }
