+        assert!(result.is_ok());
+        assert_eq!(result.unwrap(), 99);
+    }
+
+    #[tokio::test]
+    async fn timeout_expires_returns_error() {
+        let result = timeout(Duration::from_millis(10), async {
+            tokio::time::sleep(Duration::from_secs(10)).await;
